# Category: serverless_security

import os
import json
import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, CloudEvent
from azure.core.credentials import AzureNamedKeyCredential
from azure.identity import DefaultAzureCredential

# --- Configuration ---
# Blob Storage
BLOB_ACCOUNT_URL = os.environ.get("BLOB_ACCOUNT_URL") # e.g., "https://<your_storage_account_name>.blob.core.windows.net"
BLOB_CONTAINER_NAME = os.environ.get("BLOB_CONTAINER_NAME")

# Cosmos DB
COSMOS_DB_ENDPOINT = os.environ.get("COSMOS_DB_ENDPOINT") # e.g., "https://<your_cosmos_db_account_name>.documents.azure.com:443/"
COSMOS_DB_DATABASE_NAME = os.environ.get("COSMOS_DB_DATABASE_NAME")
COSMOS_DB_CONTAINER_NAME = os.environ.get("COSMOS_DB_CONTAINER_NAME")
COSMOS_DB_PARTITION_KEY_PATH = os.environ.get("COSMOS_DB_PARTITION_KEY_PATH", "/id") # Default to /id if not specified

# Event Grid
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get("EVENT_GRID_TOPIC_ENDPOINT") # e.g., "https://<your_event_grid_topic_name>.eastus-1.eventgrid.azure.net/api/events"
EVENT_GRID_TOPIC_KEY = os.environ.get("EVENT_GRID_TOPIC_KEY") # Only needed if not using Managed Identity for Event Grid, but good for local testing

# --- Managed Identity Setup ---
# DefaultAzureCredential will automatically pick up Managed Identity in Azure
# and environment variables (like AZURE_CLIENT_ID, AZURE_TENANT_ID, AZURE_CLIENT_SECRET) locally.
credential = DefaultAzureCredential()

# --- Clients Initialization ---
blob_service_client = BlobServiceClient(account_url=BLOB_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_DB_ENDPOINT, credential=credential)

# Event Grid client - prioritize Managed Identity, fallback to key for local dev if needed
if EVENT_GRID_TOPIC_KEY:
    event_grid_client = EventGridPublisherClient(
        endpoint=EVENT_GRID_TOPIC_ENDPOINT,
        credential=AzureNamedKeyCredential(EVENT_GRID_TOPIC_KEY)
    )
else:
    event_grid_client = EventGridPublisherClient(
        endpoint=EVENT_GRID_TOPIC_ENDPOINT,
        credential=credential
    )

# --- Azure Function App ---
app = func.FunctionApp()

@app.blob_trigger(
    arg_name="inputblob",
    path=BLOB_CONTAINER_NAME + "/{name}",
    connection="AzureWebJobsStorage" # This connection string is for the function app itself, not for blob_service_client
)
def process_blob_function(inputblob: func.InputStream):
    logging.info(f"Python blob trigger function processed blob\n"
                 f"Name: {inputblob.name}\n"
                 f"Size: {inputblob.length} Bytes")

    try:
        # 1. Read file content
        file_content = inputblob.read().decode('utf-8')
        blob_name = inputblob.name.split('/')[-1]
        blob_url = inputblob.uri

        logging.info(f"Content of {blob_name}:\n{file_content[:200]}...") # Log first 200 chars

        # 2. Process content (simple example: just store it)
        # In a real scenario, you'd parse, transform, analyze the content here.
        processed_data = {
            "id": os.path.splitext(blob_name)[0] + "_" + str(hash(file_content)), # Unique ID for Cosmos DB
            "blobName": blob_name,
            "blobUrl": blob_url,
            "processedTimestamp": func.get_utc_timestamp().isoformat(),
            "fileContentPreview": file_content[:500], # Store a preview or full content
            "fileLengthBytes": inputblob.length,
            "processingStatus": "Success"
        }

        # 3. Write results to Cosmos DB
        database = cosmos_client.get_database_client(COSMOS_DB_DATABASE_NAME)
        container = database.get_container_client(COSMOS_DB_CONTAINER_NAME)

        # Ensure container exists (for MVP, can create if not exists)
        try:
            container.read()
        except Exception as e:
            if "NotFound" in str(e):
                logging.warning(f"Cosmos DB container '{COSMOS_DB_CONTAINER_NAME}' not found. Attempting to create.")
                database.create_container(
                    id=COSMOS_DB_CONTAINER_NAME,
                    partition_key=PartitionKey(path=COSMOS_DB_PARTITION_KEY_PATH)
                )
                container = database.get_container_client(COSMOS_DB_CONTAINER_NAME)
            else:
                raise e

        container.upsert_item(body=processed_data)
        logging.info(f"Successfully wrote data for '{blob_name}' to Cosmos DB with id: {processed_data['id']}")

        # 4. Send notification via Event Grid
        event_data = {
            "blobName": blob_name,
            "blobUrl": blob_url,
            "cosmosDbItemId": processed_data["id"],
            "status": "Processed",
            "timestamp": processed_data["processedTimestamp"]
        }

        event = CloudEvent(
            source=blob_url,
            type="com.example.fileProcessed",
            data=event_data,
            subject=f"blob/{blob_name}"
        )
        event_grid_client.send([event])
        logging.info(f"Successfully sent Event Grid notification for '{blob_name}'")

    except Exception as e:
        logging.error(f"Error processing blob {inputblob.name}: {e}")
        # Optionally, send a failure notification to Event Grid
        error_event_data = {
            "blobName": blob_name if 'blob_name' in locals() else inputblob.name.split('/')[-1],
            "blobUrl": blob_url if 'blob_url' in locals() else inputblob.uri,
            "status": "Failed",
            "errorMessage": str(e),
            "timestamp": func.get_utc_timestamp().isoformat()
        }
        error_event = CloudEvent(
            source=inputblob.uri,
            type="com.example.fileProcessingFailed",
            data=error_event_data,
            subject=f"blob/{inputblob.name.split('/')[-1]}"
        )
        event_grid_client.send([error_event])
        raise # Re-raise the exception to mark the function execution as failed